import React, { useState } from 'react';

const DayRecord = ({ index, record, handleRemove, handleChange }) => {
  return (
    <div className="form-row">
      <div className="form-group">
        <label htmlFor={`materialName-${index}`}>z:</label>
        <input
          type="text"
          id={`materialName-${index}`}
          value={record.materialName}
          onChange={(e) => handleChange(index, 'materialName', e.target.value)}
          className="form-control"
        />
      </div>
      <div className="form-group">
        <label htmlFor={`multiplier-${index}`}>Multiplier:</label>
        <input
          type="number"
          id={`multiplier-${index}`}
          value={record.multiplier}
          onChange={(e) => handleChange(index, 'multiplier', e.target.value)}
          className="form-control"
        />
      </div>
      <div className="form-group">
        <label htmlFor={`price-${index}`}>Price:</label>
        <input
          type="number"
          id={`price-${index}`}
          value={record.price}
          onChange={(e) => handleChange(index, 'price', e.target.value)}
          className="form-control"
        />
      </div>
      <div className="form-group">
        <label htmlFor={`sum-${index}`}>Sum:</label>
        <input
          type="number"
          id={`sum-${index}`}
          value={record.price * record.multiplier}
          readOnly
          className="form-control"
        />
      </div>
      <div className="form-group">
        <label htmlFor={`comments-${index}`}>Comments:</label>
        <textarea
          id={`comments-${index}`}
          value={record.comments}
          onChange={(e) => handleChange(index, 'comments', e.target.value)}
          className="form-control"
        />
      </div>
      <button className="remove-btn" onClick={() => handleRemove(index)}>Remove</button>
    </div>
  );
};

const EmployeeDayRecord = () => {
  const [dayRecords, setDayRecords] = useState([]);

  const handleAddRecord = () => {
    setDayRecords([...dayRecords, { materialName: '', multiplier: 1, price: 0, comments: '' }]);
  };

  const handleRemove = (index) => {
    const records = [...dayRecords];
    records.splice(index, 1);
    setDayRecords(records);
  };

  const handleChange = (index, field, value) => {
    const records = [...dayRecords];
    records[index] = { ...records[index], [field]: value };
    setDayRecords(records);
  };

  const handleSave = () => {
    // Implement save functionality
    console.log('Saving', dayRecords);
  };

  return (
    <div className="material-input-form">
      <h3>Day Record</h3>
      <span className="close-popup">&times;</span>
      {dayRecords.map((record, index) => (
        <DayRecord
          key={empid}
          index={index}
          record={record}
          handleRemove={handleRemove}
          handleChange={handleChange}
        />
      ))}
      <button className="btn btn-primary add-btn" onClick={handleAddRecord}>Add Record</button>
      <button className="btn btn-success save-btn" onClick={handleSave}>Save Day Record</button>
    </div>
  );
};

export default EmployeeDayRecord;
